JSON Schema
{
  "type": "object",
  "properties": {
    "transform": {
      "type": "string",
      "const": "Analog Filter"
    },
    "input": {
      "type": "string"
    },
    "output": {
      "type": "string"
    },
    "params": {
      "type": "object",
      "properties": {
        "filter_type": {
          "type": "string",
          "enum": ["lowpass", "highpass", "bandpass", "bandstop"]
        },
        "cutoff_frequency": {
          "type": "number"
        },
        "cutoff_frequency2": {
          "type": "number"
        },
        "order": {
          "type": "integer",
          "minimum": 1,
          "maximum": 8
        },
        "ripple": {
          "type": "number"
        },
        "zero_phase": {
          "type": "boolean"
        }
      },
      "required": ["filter_type", "cutoff_frequency", "order"]
    }
  },
  "required": ["transform", "input", "output", "params"]
}

